import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [message, setMessage] = useState('');
  const [isLogin, setIsLogin] = useState(true);
  const [userId, setUserId] = useState(null);
  const [siteName, setSiteName] = useState('');
  const [siteUrl, setSiteUrl] = useState('');
  const [sites, setSites] = useState([]);

  useEffect(() => {
    if (userId) {
      axios.get(`http://localhost:5000/get-sites/${userId}`)
        .then(response => setSites(response.data.sites))
        .catch(error => console.error(error));
    }
  }, [userId]);

  const handleAuth = async (e) => {
    e.preventDefault();
    const url = isLogin ? 'http://localhost:5000/login' : 'http://localhost:5000/register';
    try {
      const response = await axios.post(url, { email, password });
      setMessage(response.data.message);
      if (!isLogin) setIsLogin(true); // Passa al login dopo la registrazione
    } catch (error) {
      setMessage(`Errore: ${error.response?.data?.error || "Impossibile completare l'operazione"}`);
    }
  };

  const handleAddSite = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('http://localhost:5000/add-site', {
        user_id: userId,
        site_name: siteName,
        site_url: siteUrl,
      });
      setSites([...sites, response.data.site]);
      setSiteName('');
      setSiteUrl('');
    } catch (error) {
      setMessage(`Errore nell'aggiungere il sito: ${error.response?.data?.error || 'Errore sconosciuto'}`);
    }
  };

  return (
    <div>
      <h1>{isLogin ? 'Login' : 'Registrazione'}</h1>
      <form onSubmit={handleAuth}>
        <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
        <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
        <button type="submit">{isLogin ? 'Login' : 'Registrati'}</button>
      </form>
      {message && <p>{message}</p>}
      <button onClick={() => setIsLogin(!isLogin)}>
        {isLogin ? 'Registrati' : 'Vai al Login'}
      </button>
      {userId && (
        <div>
          <h1>Gestione Siti</h1>
          <form onSubmit={handleAddSite}>
            <input type="text" placeholder="Nome del sito" value={siteName} onChange={(e) => setSiteName(e.target.value)} required />
            <input type="text" placeholder="URL del sito" value={siteUrl} onChange={(e) => setSiteUrl(e.target.value)} required />
            <button type="submit">Aggiungi Sito</button>
          </form>
          <h2>I tuoi siti:</h2>
          <ul>
            {sites.map((site) => (
              <li key={site.id}>{site.site_name} - {site.site_url}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default App;
